# Import the required libraries
import redis as rd # https://pypi.org/project/redis/
import requests as rq # https://requests.readthedocs.io/en/latest/?badge=latest
import json as jn # https://docs.python.org/3/library/json.html?highlight=json#module-json
import threading
import time


## Create a class for redis connection
class RedisCache:

    ## Initialize redis class
    def __init__(self, url):
        self.__conn = rd.Redis.from_url(url)
        self.ttl = 20 # Cache TTL value

    ## Function to add new key in redis
    def setKey(self, key, val):
        return self.__conn.set(key, jn.dumps(val), self.ttl)

    ## Function to get a value from cache by a key name
    def getValueByKeyName(self, key):
        res = ""
        try:
            res = self.__conn.get(key).decode()
        except Exception as err:
            pass

        return jn.loads(res) if res != '' else None

    ## Function to delete a key in redis by its name
    def deleteByKeyName(self, key):
        return self.__conn.delete(key)

    # Function to clear the cache
    def clearRedisCache(self):
        self.__conn = rd.StrictRedis()

## Create a class for user details. It will store user information in redis using key 'user:{userID}' where userID is unique ID 
## generated by users. We can't generate the same number again and again, but the number will come from remote api end point. Also we need to delete the user cache after it expires.
class UserCache(RedisCache):

    # Initialize the user details
    def __init__(self, user_id):
        url = 'http://some-url'
        super().__init__(url)

        self.__userID = str(user_id)


    ## Get the user details by ID or refresh them 
    def getUserDetailsByUserID(self):
        
        try:
            # Check is a key exists in redis for given user id.
            res = self.getValueByKeyName('user:{0}'.format(self.__userID))
            
            # If not present, get it from remote service and store the value in cache using userID as key.
            if res == None or (self.ttl > 1):

                resp = rq.get('{0}/user/{1}'.format(self.url, self.__userID))
                
                # Check if response is OK else return
                if str(resp) != '200':
                    return resp.text

                # Convert the JSON object to python dictionary and store in redis cache for 15 minutes. 
                userDetails = jn.loads(resp.content)
                res = self.setKey('user:{0}'.format(self.__userID), userDetails['data'])
                
                # Wait until 15 minutes before sending response to caller
                self.waitTillTTL()

                return resp

            else:
                print('Returning existing cached data')
                # Wait till cache expires. This will reduce the load on server for other calls.
                self.waitTillTTL()

        except Exception as err:
            pass


    ## Function that waits till cache expiry and delete it from cache. 
    def waitTillTTL(self):
        
        timeToWait = int(self.ttl*60 - (time.time() % 60)) # This will wait till the next minute.
        time.sleep(timeToWait) if self.__conn != None else print('No connection')

        self.__conn.delete(self.__userID)

## Create a class for session management that is based on redis. We have to generate session token when user logs in and store it with its expire time in redis cache. The response will send the token as a header. When user makes a new call, we will get this token from user header as a parameter and check is it present in redis or not. If its there, then we will return user details otherwise we will return the expired session message. We will also delete the token value after its expiry time. 
class SessionManager(RedisCache):
    
    def __init__(self, username = 'User'):
        url = "http://some-url"
        super().__init__(url)
        self.__username = str(username)

    ## Function to generate session
    def createSessionFor(self):
        try:
            # Get a new token from remote api service and store it with expire time in redis cache.
            resp = rq.get('{0}/token?user={1}'.format(self.url, self.__username))
            
            res = jn.loads(resp.content) if str(resp) != '200' else ''

            return {
                "session_id":res['data']['token'],
                "ttl":res["expires"]-time.time()
            }

        except Exception as err:
            pass

    ## Function to verify token
    def validateSession(self, token):
        try:
            # Check is a key exists in redis for given user id and value present in redis cache or not. This will also check is the session expired or not. If expired then return it from cache otherwise delete this expired value form redis cache
            res = self.__conn.get(token)

            if (self.ttl > 1):
                print('Valid token, no need to refresh')
                # Wait until 15 minutes before sending response to caller
                self.waitTillTTL()

                return jn.loads(res)['data']
            else:
                
                self.__conn.delete(token)
                raise Exception('Session Expired')

        except Exception as err:

            print(err)

    ## Function that waits till cache expiry and delete it from cache. 
    def waitTillTTL(self):
        
        timeToWait = int(self.ttl*60 - (time.time() % 60)) # This will wait till the next minute.
        time.sleep(timeToWait) if self.__conn != None else print('No connection')

        self.__conn.delete(token)